def parse_saml_response(saml_response):
    try:
        # Decode base64 encoded SAML response
        decoded_response = base64.b64decode(saml_response)
        
        # Parse XML
        root = ET.fromstring(decoded_response)
        
        # Validate assertion presence
        assertions = root.findall('.//saml:Assertion', namespaces=SAML_NAMESPACES)
        if not assertions:
            raise ValueError("No assertions found in SAML response")
        
        # Extract user attributes from first assertion
        assertion = assertions[0]
        user_attributes = extract_user_attributes(assertion)
        
        # Validate assertion structure
        validate_assertion(assertion)
        
        return user_attributes
        
    except Exception as e:
        raise ValueError(f"Failed to parse SAML response: {str(e)}")

def extract_user_attributes(assertion):
    attributes = {}
    
    # Extract subject (user identifier)
    subject = assertion.find('.//saml:Subject', namespaces=SAML_NAMESPACES)
    if subject is not None:
        name_id = subject.find('.//saml:NameID', namespaces=SAML_NAMESPACES)
        if name_id is not None:
            attributes['user_id'] = name_id.text
    
    # Extract attributes
    attribute_statements = assertion.findall('.//saml:AttributeStatement', namespaces=SAML_NAMESPACES)
    
    for stmt in attribute_statements:
        attributes_elements = stmt.findall('.//saml:Attribute', namespaces=SAML_NAMESPACES)
        for attr in attributes_elements:
            attr_name = attr.get('Name')
            attr_values = attr.findall('.//saml:AttributeValue', namespaces=SAML_NAMESPACES)
            if attr_values:
                attributes[attr_name] = [val.text for val in attr_values]
    
    return attributes

def validate_assertion(assertion):
    # Check that assertion has required elements
    issuer = assertion.find('.//saml:Issuer', namespaces=SAML_NAMESPACES)
    if issuer is None:
        raise ValueError("Assertion missing Issuer element")
    
    subject = assertion.find('.//saml:Subject', namespaces=SAML_NAMESPACES)
    if subject is None:
        raise ValueError("Assertion missing Subject element")
    
    conditions = assertion.find('.//saml:Conditions', namespaces=SAML_NAMESPACES)
    if conditions is None:
        raise ValueError("Assertion missing Conditions element")
    
    # Validate time constraints
    not_before = conditions.get('NotBefore')
    not_on_or_after = conditions.get('NotOnOrAfter')
    
    if not_before:
        not_before_dt = datetime.fromisoformat(not_before.replace('Z', '+00:00'))
        if not_before_dt > datetime.utcnow():
            raise ValueError("Assertion not yet valid")
    
    if not_on_or_after:
        not_on_or_after_dt = datetime.fromisoformat(not_on_or_after.replace('Z', '+00:00'))
        if not_on_or_after_dt < datetime.utcnow():
            raise ValueError("Assertion expired")

